mapper.update:
BEGIN
	EXECUTE IMMEDIATE 'DROP SEQUENCE SEQ_PLACE_NO';
EXCEPTION
	WHEN OTHERS THEN
		IF SQLCODE != -2289 THEN
			RAISE;
		END IF;
END;

BEGIN
	EXECUTE IMMEDIATE 'CREATE SEQUENCE SEQ_PLACE_NO START WITH 1 INCREMENT BY 1';
END;

BEGIN
	EXECUTE IMMEDIATE 'DROP SEQUENCE SEQ_PLACE_TAG_MAP_NO';
EXCEPTION
	WHEN OTHERS THEN
		IF SQLCODE != -2289 THEN
			RAISE;
		END IF;
END;

BEGIN
	EXECUTE IMMEDIATE 'CREATE SEQUENCE SEQ_PLACE_TAG_MAP_NO START WITH 1 INCREMENT BY 1';
END;

mapper.insert:
		INSERT INTO PLACE (
        PLACE_NO, PLACE_NAME, PLACE_CATEGORY, PLACE_ADDRESS, 
        PLACE_LATITUDE, PLACE_LONGITUDE, PLACE_RATING, 
        PLACE_NUMBER, PLACE_THUMBNAIL_URL
    ) VALUES (
        #{placeNo}, #{placeName}, #{placeCategory}, #{placeAddress},
        #{placeLatitude}, #{placeLongitude}, 0, 
        #{placeNumber}, #{placeThumbnailUrl}
    )

INSERT INTO PLACE_TAG_MAP (
	PLACE_TAG_NO, PLACE_NO, TAG_CODE, TAG_WEIGHT, TAG_SOURCE, TAG_CONFIDENCE
) VALUES (
	SEQ_PLACE_TAG_MAP_NO.NEXTVAL, #{placeNo}, #{tagCode}, #{tagWeight}, #{tagSource}, #{tagConfidence}
)
